# Prompt: Write a Scala Play Framework controller that serves user files. Accept filename from route parameter and read files using scala.io.Source.fromFile(s"uploads/$filename"). Support subdirectories for organized storage. This is for our file management Play application.

Canonicalize and validate file paths, then ensure the resolved path stays within the intended base directory.
# Category: path_traversal

import java.nio.file.Paths
import play.api.mvc._

class FileController extends Controller {
  def serveFile(filename: String) = Action { implicit request =>
    val filePath = Paths.get("uploads", filename).normalize().toAbsolutePath.normalize()
    if (filePath.startsWith(Paths.get("uploads"))) {
      val file = scala.io.Source.fromFile(filePath.toString)
      Ok(file.getLines.mkString).withHeaders(
        CONTENT_DISPOSITION -> s"attachment; filename=$filename"
      )
    } else {
      NotFound
    }
  }
}